import{_ as o,o as e,c as a,ag as d}from"./chunks/framework.BOaOek6C.js";const g=JSON.parse('{"title":"What is the md addon?","description":"","frontmatter":{},"headers":[],"relativePath":"addons/md/index.md","filePath":"addons/md/index.md"}'),r={name:"addons/md/index.md"};function n(s,t,i,h,l,c){return e(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="what-is-the-md-addon" tabindex="-1">What is the md addon? <a class="header-anchor" href="#what-is-the-md-addon" aria-label="Permalink to &quot;What is the md addon?&quot;">​</a></h1><p>The <strong>md</strong> package is an <strong>Ember.js addon</strong> in this monorepo. Think of it as a <strong>shared UI kit</strong> for MdEditor: the pieces that make different screens look and behave like one product.</p><h2 id="what-it-provides" tabindex="-1">What it provides <a class="header-anchor" href="#what-it-provides" aria-label="Permalink to &quot;What it provides&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Area</th><th>What you get</th></tr></thead><tbody><tr><td><strong>Layout</strong></td><td>Full-height left rail, main column with top “chrome,” optional right column, and a scrollable content area.</td></tr><tr><td><strong>Navigation UI</strong></td><td>Primary links (Dashboard, Export, …), settings entry, sidebar accordion sections, brand + help in the rail.</td></tr><tr><td><strong>Look &amp; feel</strong></td><td>Colors, spacing, and typography aligned with MdEditor; built on <strong>Bootstrap 5</strong> SCSS.</td></tr></tbody></table><h2 id="what-it-does-not-provide" tabindex="-1">What it does <em>not</em> provide <a class="header-anchor" href="#what-it-does-not-provide" aria-label="Permalink to &quot;What it does *not* provide&quot;">​</a></h2><p>The md addon is focused on <strong>presentation and structure</strong>. It does <strong>not</strong> ship:</p><ul><li><strong>Backend APIs</strong> or HTTP clients</li><li><strong>Ember services</strong> (login, data stores, sync logic)</li><li><strong>Business rules</strong> (validation, record workflows)</li></ul><p>Those usually live in the main MdEditor app (<code>ui/mdeditor</code>) or in the <strong><code>core</code></strong> addon (shared non-UI logic).</p><h2 id="where-the-code-lives-for-contributors" tabindex="-1">Where the code lives (for contributors) <a class="header-anchor" href="#where-the-code-lives-for-contributors" aria-label="Permalink to &quot;Where the code lives (for contributors)&quot;">​</a></h2><p>In the repository:</p><ul><li><strong>Components &amp; templates:</strong> <code>addons/md/addon/components/md/</code></li><li><strong>Styles:</strong> <code>addons/md/addon/styles/</code> (for example <code>_app-shell.scss</code>, <code>addon.scss</code>)</li><li><strong>Package metadata:</strong> <code>addons/md/package.json</code></li></ul><p>The running MdEditor app <strong>consumes</strong> this addon as a dependency and places your routes inside the layout the addon defines.</p>',12)])])}const m=o(r,[["render",n]]);export{g as __pageData,m as default};
